<?php
$pageTitle='Document Folders';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('document_folders');
$pdo=getDB();
if($_SERVER['REQUEST_METHOD']==='POST'){
  try{
    $action=(string)($_POST['action']??'folder');
    $user=currentUser();
    if($action==='category'){
      $code=trim((string)$_POST['category_code']) ?: nextScopedDocumentNumber($pdo,'document_category',setting('document_category_prefix','DCAT'),operationalScope($pdo));
      $pdo->prepare('INSERT INTO '.table('document_categories').' (category_code,category_name,module_key,requires_expiry,requires_approval,default_retention_days,status,created_by) VALUES (?,?,?,?,?,?,?,?)')->execute([$code,trim((string)$_POST['category_name']),trim((string)$_POST['module_key']),(int)($_POST['requires_expiry']??0),(int)($_POST['requires_approval']??0),(int)($_POST['default_retention_days']??0),trim((string)$_POST['status']),(int)($user['id']??0)?:null]);
      flash('success','Document category created.');
    } else {
      $code=trim((string)$_POST['folder_code']) ?: nextScopedDocumentNumber($pdo,'document_folder',setting('document_folder_prefix','FLD'),operationalScope($pdo));
      $pdo->prepare('INSERT INTO '.table('document_folders').' (parent_id,company_id,branch_id,folder_code,folder_name,folder_path,module_key,visibility,status,sort_order,created_by) VALUES (?,?,?,?,?,?,?,?,?,?,?)')->execute([(int)($_POST['parent_id']??0)?:null,(int)($_POST['company_id']??0)?:null,(int)($_POST['branch_id']??0)?:null,$code,trim((string)$_POST['folder_name']),trim((string)$_POST['folder_path']),trim((string)$_POST['module_key']),trim((string)$_POST['visibility']),trim((string)$_POST['status']),(int)$_POST['sort_order'],(int)($user['id']??0)?:null]);
      flash('success','Document folder created.');
    }
  }catch(Throwable $e){recordSystemError($pdo,$e,['page'=>'document-folders']);flash('error',$e->getMessage());}
  redirect(ADMIN_URL.'/erp/document-folders.php');
}
$folders=$pdo->query('SELECT f.*,p.folder_name parent_name FROM '.table('document_folders').' f LEFT JOIN '.table('document_folders').' p ON p.id=f.parent_id ORDER BY f.module_key,f.sort_order,f.folder_name')->fetchAll();
$categories=$pdo->query('SELECT * FROM '.table('document_categories').' ORDER BY module_key,category_name')->fetchAll();
include dirname(__DIR__).'/header.php';
?>
<div class="d-flex flex-wrap justify-content-between align-items-end gap-3 mb-4"><div><div class="erp-kicker">Document Structure</div><h2 class="h4 mb-1">Document Folders & Categories</h2><p class="text-secondary mb-0">Manage folder tree, document categories, retention, expiry and approval defaults.</p></div></div>
<div class="row g-4"><div class="col-xl-4"><form method="post" class="card-admin p-4 mb-4"><h2 class="h5 mb-3">Create Folder</h2><select class="form-select mb-2" name="parent_id"><option value="">No parent</option><?php foreach($folders as $f): ?><option value="<?php echo (int)$f['id']; ?>"><?php echo esc($f['folder_name']); ?></option><?php endforeach; ?></select><input class="form-control mb-2" name="folder_code" placeholder="Auto code"><input class="form-control mb-2" name="folder_name" placeholder="Folder name" required><input class="form-control mb-2" name="folder_path" placeholder="/Finance/Invoices"><select class="form-select mb-2" name="module_key"><?php foreach(documentModuleOptions() as $k=>$v): ?><option value="<?php echo esc($k); ?>"><?php echo esc($v); ?></option><?php endforeach; ?></select><select class="form-select mb-2" name="visibility"><option>public</option><option selected>internal</option><option>restricted</option></select><select class="form-select mb-2" name="status"><option>active</option><option>inactive</option></select><input class="form-control mb-3" type="number" name="sort_order" value="10"><button class="btn btn-brand w-100">Create Folder</button></form><form method="post" class="card-admin p-4"><input type="hidden" name="action" value="category"><h2 class="h5 mb-3">Create Category</h2><input class="form-control mb-2" name="category_code" placeholder="Auto code"><input class="form-control mb-2" name="category_name" placeholder="Category name" required><select class="form-select mb-2" name="module_key"><?php foreach(documentModuleOptions() as $k=>$v): ?><option value="<?php echo esc($k); ?>"><?php echo esc($v); ?></option><?php endforeach; ?></select><select class="form-select mb-2" name="requires_expiry"><option value="0">No expiry required</option><option value="1">Expiry required</option></select><select class="form-select mb-2" name="requires_approval"><option value="0">No approval required</option><option value="1">Approval required</option></select><input class="form-control mb-2" type="number" name="default_retention_days" value="365"><select class="form-select mb-3" name="status"><option>active</option><option>inactive</option></select><button class="btn btn-outline-primary w-100">Create Category</button></form></div><div class="col-xl-8"><div class="table-wrap table-responsive mb-4"><h2 class="h5 mb-3">Folders</h2><table class="table"><thead><tr><th>Folder</th><th>Parent</th><th>Module</th><th>Visibility</th><th>Status</th></tr></thead><tbody><?php foreach($folders as $f): ?><tr><td><strong><?php echo esc($f['folder_code']); ?></strong><div class="small text-secondary"><?php echo esc($f['folder_name'].' · '.$f['folder_path']); ?></div></td><td><?php echo esc($f['parent_name']?:'-'); ?></td><td><?php echo esc($f['module_key']); ?></td><td><?php echo esc($f['visibility']); ?></td><td><span class="badge bg-<?php echo esc(statusTone($f['status'])); ?>"><?php echo esc($f['status']); ?></span></td></tr><?php endforeach; ?></tbody></table></div><div class="table-wrap table-responsive"><h2 class="h5 mb-3">Categories</h2><table class="table"><thead><tr><th>Category</th><th>Module</th><th>Expiry</th><th>Approval</th><th>Status</th></tr></thead><tbody><?php foreach($categories as $c): ?><tr><td><strong><?php echo esc($c['category_code']); ?></strong><div class="small text-secondary"><?php echo esc($c['category_name']); ?></div></td><td><?php echo esc($c['module_key']); ?></td><td><?php echo $c['requires_expiry']?'Yes':'No'; ?></td><td><?php echo $c['requires_approval']?'Yes':'No'; ?></td><td><span class="badge bg-<?php echo esc(statusTone($c['status'])); ?>"><?php echo esc($c['status']); ?></span></td></tr><?php endforeach; ?></tbody></table></div></div></div>
<?php include dirname(__DIR__).'/footer.php'; ?>